  const results = [];
  for (const attr of attrs) {
    const elements = await page.evaluate((a) => {
      return Array.from(document.querySelectorAll('[' + a + ']')).map(el => ({
        attribute: a,
        value: el.getAttribute(a),
        tag: el.tagName,
        role: el.getAttribute('role') || '',
        type: el.getAttribute('type') || '',
        text: el.textContent?.trim().substring(0, 50) || ''
      }));
    }, attr);
    results.push(...elements);
  }
  const detected = results.length > 0 ? results[0].attribute : 'none';
  return { detected_attr: detected, elements: results.slice(0, 50) };
}

